INSERT INTO `coursetarget` VALUES ('17a8dc20-59a9-402d-a9b5-db369533e05b', 'cmnctuqog0000f8ut0rkcx2ji', 2, '课程目标3', '指标点12.1能在社会与技术发展的大背景下，认识到自主和终身学习的必要性；										\n', '指标点12.1能在社会与技术发展的大背景下，认识到自主和终身学习的必要性；										\n', 'L', 0.3000, 1.0000, 0.0000, 1.0000, 1.0000, 0.0000, 0.0000);
INSERT INTO `coursetarget` VALUES ('2b7ea27d-203c-4b5a-9433-5f591a223a8f', 'cmnbnfcip00003outwe0r8opt', 4, '课程目标5', '指标点10.2 了解软件工程领域的国际发展趋势、研究热点，理解和尊重世界不同语言、文化的差异性和多样性；										\n', '指标点10.2 了解软件工程领域的国际发展趋势、研究热点，理解和尊重世界不同语言、文化的差异性和多样性；										\n', 'L', 0.0500, 1.0000, 0.0000, 1.0000, 1.0000, 0.0000, 0.0000);
INSERT INTO `coursetarget` VALUES ('2f7bc355-1169-4547-829f-94c9a1d9ed95', 'cmnbi4ios0000p8ut50bg75ro', 2, '课程目标3', '学生能够运用数据结构与算法的基本原理，识别和判断复杂软件工程问题中数据结构使用和算法选择的关键环节。										\n', '学生能够运用数据结构与算法的基本原理，识别和判断复杂软件工程问题中数据结构使用和算法选择的关键环节。										\n', 'M', 0.2500, 0.0000, 1.0000, 1.0000, 0.8000, 0.2000, 0.0000);
INSERT INTO `coursetarget` VALUES ('4d44b3e1-208c-49bc-9222-041d44ab1aa2', 'cmnbi4ios0000p8ut50bg75ro', 3, '课程目标4', '学生结合具体应用案例，能够认识到有多种逻辑结构和存储结构可供选择，通过网络、文献、大模型等方法寻求应用案例的解决方案。										\n', '学生结合具体应用案例，能够认识到有多种逻辑结构和存储结构可供选择，通过网络、文献、大模型等方法寻求应用案例的解决方案。										\n', 'H', 0.3000, 1.0000, 0.0000, 1.0000, 0.8000, 0.2000, 0.0000);
INSERT INTO `coursetarget` VALUES ('630f1309-a382-44b7-9b0b-2f298ce382ab', 'cmnbnfcip00003outwe0r8opt', 1, '课程目标2', '指标点2.2 能基于相关科学原理、离散等数学模型及UML建模等方法，正确表达复杂软件工程问题；										\n', '指标点2.2 能基于相关科学原理、离散等数学模型及UML建模等方法，正确表达复杂软件工程问题；										\n', 'H', 0.2500, 0.6000, 0.4000, 1.0000, 1.0000, 0.0000, 0.0000);
INSERT INTO `coursetarget` VALUES ('6da644e5-6761-4f70-ab6b-f125c9e6b088', 'cmnbi4ios0000p8ut50bg75ro', 0, '课程目标1', '学生具备分析线性表、栈和队列、串、数组和广义表、树和二叉树、图等各种基本数据结构的能力；能够针对具体问题，通过定义抽象数学模型、算法并求解。										\n', '学生具备分析线性表、栈和队列、串、数组和广义表、树和二叉树、图等各种基本数据结构的能力；能够针对具体问题，通过定义抽象数学模型、算法并求解。										\n', 'L', 0.1500, 0.5000, 0.5000, 1.0000, 0.8000, 0.2000, 0.0000);
INSERT INTO `coursetarget` VALUES ('7c8a9f64-14a8-4a49-8a12-1fc942c06f02', 'cmnbnfcip00003outwe0r8opt', 2, '课程目标3', '指标点3.1掌握软件工程设计和产品开发全周期、全流程的设计方法和技术，了解影响设计软件目标和技术方案的各种因素；										\n', '指标点3.1掌握软件工程设计和产品开发全周期、全流程的设计方法和技术，了解影响设计软件目标和技术方案的各种因素；										\n', 'H', 0.2500, 0.6000, 0.4000, 1.0000, 1.0000, 0.0000, 0.0000);
INSERT INTO `coursetarget` VALUES ('bfc6f1da-201c-463b-9481-0143b0a8fc44', 'cmnbnfcip00003outwe0r8opt', 3, '课程目标4', '\"指标点5.1了解软件工程常用的设计、建模、测试、交互、集成开发环境等软硬件设备、信息技术工具和工程工具的使用原理和方法，并理解其局限性；\n\"										\n', '\"指标点5.1了解软件工程常用的设计、建模、测试、交互、集成开发环境等软硬件设备、信息技术工具和工程工具的使用原理和方法，并理解其局限性；\n\"										\n', 'M', 0.1500, 1.0000, 0.0000, 1.0000, 1.0000, 0.0000, 0.0000);
INSERT INTO `coursetarget` VALUES ('d6ed1a56-0220-46ac-b0fc-71a30a0035eb', 'cmnctuqog0000f8ut0rkcx2ji', 0, '课程目标1', '指标点7.1 知晓和理解环境保护和可持续发展的理念和内涵；										\n', '指标点7.1 知晓和理解环境保护和可持续发展的理念和内涵；										\n', 'M', 0.3000, 1.0000, 0.0000, 1.0000, 1.0000, 0.0000, 0.0000);
