INSERT INTO `coursetarget` VALUES ('e756d519-4849-4f75-b00a-17db94259a9c', 'cmnbi4ios0000p8ut50bg75ro', 1, '课程目标2', '针对工程应用问题，学生能够利用抽象数据结构思维的能力，比较和综合各种方案在逻辑结构、存储结构的优劣。										\n', '针对工程应用问题，学生能够利用抽象数据结构思维的能力，比较和综合各种方案在逻辑结构、存储结构的优劣。										\n', 'H', 0.3000, 0.5000, 0.5000, 1.0000, 0.8000, 0.2000, 0.0000);
